async function sendEmailJS(reservation) {
  const { confNum, name, phone, email, hayName, quantity, total,
          payMethod, loadType, pickupDate, pickupTime, notes, submittedAt } = reservation;
  const payLabels = { cash:"Cash (No GST)", etransfer:"E-Transfer", cheque:"Cheque" };

  const body = [
    `Confirmation #: ${confNum}`,
    `Name: ${name}`,
    `Phone: ${phone}`,
    `Email: ${email || "—"}`,
    `Hay Type: ${hayName}`,
    `Quantity: ${quantity} bale${quantity !== 1 ? "s" : ""}`,
    `Load Type: ${loadType}`,
    `Pick-Up Date: ${pickupDate}`,
    `Pick-Up Time: ${pickupTime}`,
    `Payment: ${payLabels[payMethod]}`,
    `Total: $${total.toFixed(2)}`,
    `Notes: ${notes || "None"}`,
    `Submitted: ${submittedAt}`,
  ].join("\n");

  const subject = encodeURIComponent(`New Hay Reservation ${confNum} — ${name}`);
  const bodyEnc = encodeURIComponent(body);
  const toList  = NOTIFY_EMAILS.join(",");

  // Try EmailJS first
  try {
    const res = await fetch("https://api.emailjs.com/api/v1.0/email/send", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        service_id:   EJS_SERVICE_ID,
        template_id:  EJS_TEMPLATE_ID,
        user_id:      EJS_PUBLIC_KEY,
        accessToken:  EJS_PRIVATE_KEY,
        template_params: {
          to_email: NOTIFY_EMAILS[0],
          conf_num: confNum, cust_name: name, cust_phone: phone,
          cust_email: email || "—", hay_type: hayName,
          quantity: `${quantity} bale${quantity !== 1 ? "s" : ""}`,
          load_type: loadType, pickup_date: pickupDate, pickup_time: pickupTime,
          payment: payLabels[payMethod], total: `$${total.toFixed(2)}`,
          notes: notes || "None", submitted_at: submittedAt,
        },
      }),
    });
    const txt = await res.text();
    if (res.ok) {
      console.log("EmailJS success:", txt);
      return; // worked!
    }
    console.warn("EmailJS failed:", res.status, txt);
  } catch(err) {
    console.warn("EmailJS fetch failed:", err.message);
  }

  // Fallback: open mailto so the ranch can send manually
  window.open(`mailto:${toList}?subject=${subject}&body=${bodyEnc}`, "_blank");
  throw new Error("EmailJS unavailable — your email app has been opened with the reservation details. Please send it to notify the ranch.");
}

